 {"id":"bd-2gz","title":"Implement TestConsole for output capture in tests","description":"## Purpose and Rationale

Create a TestConsole that captures all output for assertion in tests instead of writing to stderr. This enables testing rich output without polluting test output and allows assertions on rendered content.

## Background

Testing code that produces rich output is challenging because:
1. ANSI codes make string comparison difficult
2. Output goes to stderr, polluting test output
3. Hard to verify specific content was rendered

TestConsole solves this by capturing output to an internal buffer that can be inspected.

## Technical Specification

### Core Structure

```rust
// crates/fastmcp-console/src/testing/test_console.rs

use std::sync::{Arc, Mutex};
use crate::console::{FastMcpConsole, ConsoleOutput};
use crate::theme::FastMcpTheme;
use crate::context::DisplayContext;
use strip_ansi_escapes::strip;

/// A Console that captures output for testing
#[derive(Debug, Clone)]
pub struct TestConsole {
    inner: FastMcpConsole,
    buffer: Arc<Mutex<TestBuffer>>,
}

#[derive(Debug, Default)]
struct TestBuffer {
    lines: Vec<String>,
    raw_lines: Vec<String>, // With ANSI codes
}

impl TestConsole {
    /// Create a new test console that captures output
    pub fn new() -> Self {
        let context = DisplayContext::new_agent(); // No rich by default
        let buffer = Arc::new(Mutex::new(TestBuffer::default()));

        Self {
            inner: FastMcpConsole::new_with_writer(
                FastMcpTheme::default(),
                context,
                BufferWriter(buffer.clone()),
            ),
            buffer,
        }
    }

    /// Create a test console that renders rich output (for visual testing)
    pub fn new_rich() -> Self {
        let context = DisplayContext::new_human();
        let buffer = Arc::new(Mutex::new(TestBuffer::default()));

        Self {
            inner: FastMcpConsole::new_with_writer(
                FastMcpTheme::default(),
                context,
                BufferWriter(buffer.clone()),
            ),
            buffer,
        }
    }

    /// Get the underlying console for passing to renderers
    pub fn console(&self) -> &FastMcpConsole {
        &self.inner
    }

    /// Get all captured output (ANSI codes stripped)
    pub fn output(&self) -> Vec<String> {
        self.buffer.lock().unwrap().lines.clone()
    }

    /// Get all captured output (with ANSI codes)
    pub fn raw_output(&self) -> Vec<String> {
        self.buffer.lock().unwrap().raw_lines.clone()
    }

    /// Get output as a single string
    pub fn output_string(&self) -> String {
        self.output().join("\n")
    }

    /// Check if output contains a string (case-insensitive)
    pub fn contains(&self, needle: &str) -> bool {
        let output = self.output_string().to_lowercase();
        output.contains(&needle.to_lowercase())
    }

    /// Check if output contains all of the given strings
    pub fn contains_all(&self, needles: &[&str]) -> bool {
        needles.iter().all(|n| self.contains(n))
    }

    /// Check if output matches a regex pattern
    #[cfg(feature = "regex")]
    pub fn matches(&self, pattern: &str) -> bool {
        let re = regex::Regex::new(pattern).expect("Invalid regex pattern");
        re.is_match(&self.output_string())
    }

    /// Assert that output contains a string
    pub fn assert_contains(&self, needle: &str) {
        assert\!(
            self.contains(needle),
            "Output did not contain '{}'. Actual output:\n{}",
            needle,
            self.output_string()
        );
    }

    /// Assert that output does NOT contain a string
    pub fn assert_not_contains(&self, needle: &str) {
        assert\!(
            \!self.contains(needle),
            "Output unexpectedly contained '{}'. Actual output:\n{}",
            needle,
            self.output_string()
        );
    }

    /// Assert output has specific number of lines
    pub fn assert_line_count(&self, expected: usize) {
        let actual = self.output().len();
        assert_eq\!(
            actual, expected,
            "Expected {} lines but got {}. Actual output:\n{}",
            expected, actual, self.output_string()
        );
    }

    /// Clear the buffer
    pub fn clear(&self) {
        let mut buf = self.buffer.lock().unwrap();
        buf.lines.clear();
        buf.raw_lines.clear();
    }

    /// Print output for debugging (in tests)
    pub fn debug_print(&self) {
        eprintln\!("=== TestConsole Output ===");
        for (i, line) in self.output().iter().enumerate() {
            eprintln\!("{:3}: {}", i + 1, line);
        }
        eprintln\!("==========================");
    }
}

/// Writer that captures to a buffer
struct BufferWriter(Arc<Mutex<TestBuffer>>);

impl std::io::Write for BufferWriter {
    fn write(&mut self, buf: &[u8]) -> std::io::Result<usize> {
        let s = String::from_utf8_lossy(buf);
        let mut buffer = self.0.lock().unwrap();

        // Store raw (with ANSI)
        buffer.raw_lines.extend(s.lines().map(String::from));

        // Store stripped (without ANSI)
        let stripped = strip(buf);
        let stripped_str = String::from_utf8_lossy(&stripped);
        buffer.lines.extend(stripped_str.lines().map(String::from));

        Ok(buf.len())
    }

    fn flush(&mut self) -> std::io::Result<()> {
        Ok(())
    }
}
```

